<template>
  <div>
    <v-col lg="10" xl="8" class="mx-auto">
      <h1 class="mb-5">Compare Pokemons</h1>
      <v-card elevation="5">
        <v-card-title>
          Pokemons
          <v-spacer></v-spacer>
          <v-text-field
            v-model="search"
            append-icon="mdi-magnify"
            label="Search"
            single-line
            hide-details
          ></v-text-field>
        </v-card-title>
        <v-data-table
          v-model="selected"
          :headers="headers"
          :search="search"
          :items="statsOnlyCompareList"
          item-key="image"
          :multi-sort="true"
          :single-select="false"
          show-select
          :footer-props="{
            showFirstLastPage: true,
            firstIcon: 'mdi-arrow-collapse-left',
            lastIcon: 'mdi-arrow-collapse-right',
            prevIcon: 'mdi-minus',
            nextIcon: 'mdi-plus',
          }"
        >
          <template v-slot:item.total="{ item }">
            <v-chip :color="getTotalColor(item.total)" class="px-5" dark>
              {{ item.total }}
            </v-chip>
          </template>
          <template v-slot:item.image="{ item }">
            <v-img
              class="white--text align-end ma-2"
              contain
              :src="
                `https://pokeres.bastionbot.org/images/pokemon/${item.image}.png`
              "
              :lazy-src="
                `https://pokeres.bastionbot.org/images/pokemon/${item.image}.png`
              "
              :alt="item.name"
              width="100px"
            >
            </v-img>
          </template>
        </v-data-table>

        <div class="mx-4">
          <v-btn
            color="error"
            class="ma-2"
            :disabled="!isRemovable"
            @click="removeSelectedPokemons"
          >
            Remove selected
          </v-btn>

          <v-badge
            bordered
            color="primary"
            :content="selected.length.toString()"
            class="ma-2"
            offset-x="10"
            offset-y="10"
          >
            <v-btn
              color="warning"
              :disabled="selected.length === 0"
              @click="selected = []"
            >
              Unselected
            </v-btn>
          </v-badge>
        </div>

        <v-simple-table>
          <template v-slot:default>
            <thead>
              <tr>
                <th></th>
                <th>Total</th>
              </tr>
            </thead>
            <tbody>
              <tr>
                <th>Min:</th>
                <td>{{ minTotal }}</td>
              </tr>
              <tr>
                <th>Between min &amp; agv:</th>
                <td>{{ betweenMinAndAvgMark }}</td>
              </tr>
              <tr>
                <th>Average:</th>
                <td>{{ averageTotal }}</td>
              </tr>
              <tr>
                <th>Between max &amp; avg:</th>
                <td>{{ betweenMaxAndAvgMark }}</td>
              </tr>
              <tr>
                <th>Max:</th>
                <td>{{ maxTotal }}</td>
              </tr>
            </tbody>
          </template>
        </v-simple-table>
      </v-card>

      <v-card elevation="5" class="mt-6">
        <v-card-title>
          Radar Chart
          <v-spacer></v-spacer>
        </v-card-title>
        <v-divider></v-divider>
        <v-card-text>
          <radar-chart
            :chart-data="chartData"
            :options="chartOptions"
          ></radar-chart
        ></v-card-text>
      </v-card>
    </v-col>
  </div>
</template>

<script>
import { mapState } from "vuex";
import RadarChart from "@/components/RadarChart.vue";

export default {
  components: {
    RadarChart,
  },
  computed: {
    ...mapState(["comparePokemons"]),
    isRemovable() {
      return this.selected.length > 0;
    },
    statsOnlyCompareList() {
      return this.comparePokemons.map((item) => {
        var obj = { name: item.name, image: item.id, id: item.id };
        var total = 0;
        item.stats.forEach((stat) => {
          obj[stat.name] = stat.baseStat;
          total += stat.baseStat;
        });
        return { ...obj, total };
      });
    },
    minTotal() {
      return Math.min(...this.statsOnlyCompareList.map((item) => item.total));
    },
    maxTotal() {
      return Math.max(...this.statsOnlyCompareList.map((item) => item.total));
    },
    averageTotal() {
      var totals = this.statsOnlyCompareList.map((item) => item.total);
      return Math.round(
        totals.reduce((total, value) => total + value, 0) / totals.length
      );
    },
    betweenMinAndAvgMark() {
      return Math.round((this.minTotal + this.averageTotal) / 2);
    },
    betweenMaxAndAvgMark() {
      return Math.round((this.maxTotal + this.averageTotal) / 2);
    },
    ...mapState([]),
  },
  data() {
    return {
      search: "",
      selected: [],
      headers: [
        {
          text: "Image",
          align: "start",
          sortable: false,
          value: "image",
        },
        {
          text: "Name",
          align: "start",
          sortable: false,
          value: "name",
        },
        { text: "HP", value: "hp" },
        { text: "Attack", value: "attack" },
        { text: "Defense", value: "defense" },
        { text: "Speed", value: "speed" },
        { text: "Special Attack", value: "special-attack" },
        { text: "Special Defense", value: "special-defense" },
        { text: "Total", value: "total" },
      ],
      labels: [
        "hp",
        "attack",
        "defense",
        "speed",
        "special-attack",
        "special-defense",
      ],
      chartData: {
        labels: [
          "hp",
          "attack",
          "defense",
          "speed",
          "special-attack",
          "special-defense",
        ],
      },
      chartOptions: {
        responsive: true,
        maintainAspectRatio: false,
        scale: {
          ticks: {
            beginAtZero: true,
            showLabelBackdrop: false,
          },
          pointLabels: {},
          gridLines: {},
          angleLines: {},
        },
      },
    };
  },
  watch: {
    selected(newValue, oldValue) {
      this.chartData = {
        labels: this.labels,
        datasets: [],
      };
      for (var i = 0; i < newValue.length; i++) {
        var index = 0;
        var data = [];
        this.labels.forEach((name) => {
          data[index] = newValue[i][name];
          index++;
        });
        this.chartData.datasets.push({
          label: newValue[i].name,
          backgroundColor: this.getRandomColorChart(64),
          data,
        });
      }
    },
  },
  methods: {
    removeSelectedPokemons() {
      if (this.isRemovable) {
        this.selected.forEach((item) => {
          this.$store.commit("removeFromComparePokemons", item);
        });
        this.selected = [];
      }
    },
    getTotalColor(value) {
      if (value < this.betweenMinAndAvgMark) {
        return "error";
      } else if (value > this.betweenMaxAndAvgMark) {
        return "success";
      } else {
        return "warning";
      }
    },
    checkAlpha(alpha) {
      alpha = parseInt(alpha);
      if (alpha == NaN) {
        alpha = 255;
      }
      if (alpha < 16) {
        alpha = 16;
      }
      if (alpha > 255) {
        alpha = 255;
      }
      return alpha;
    },
    getRandomColorChart(alpha = 255) {
      alpha = this.checkAlpha(alpha);
      return `#${Math.floor(Math.random() * 16777215)
        .toString(16)
        .padStart(6, 0)}${alpha.toString(16).padStart(2.0)}`.toUpperCase();
    },
  },
};
</script>

